import csv, os, re, shutil
import fitz, pytesseract
from PIL import Image

DOCS='/app/documents'
INV='/app/invoices'
OTH='/app/other'

invoice_indicators = [
    r'\binvoice\b',
    r'\bbill to\b',
    r'\binvoice number\b',
    r'\bamount due\b',
    r'\bdate of issue\b',
    r'\btotalprice\b',
]

num_pat = re.compile(r'(?<!\d)(?:\d{1,3}(?:[ ,]\d{3})+|\d+)(?:[.,]\d+)?(?!\d)')


def extract_text(path):
    if path.lower().endswith('.pdf'):
        doc = fitz.open(path)
        return '\n'.join(page.get_text() for page in doc)
    return pytesseract.image_to_string(Image.open(path), config='--psm 6')


def normalize_number(s):
    s = s.strip()
    s = re.sub(r'[^0-9,.-]', '', s.replace(' ', ''))
    if not s:
        return None
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '').replace(',', '.')
        else:
            s = s.replace(',', '')
    elif ',' in s:
        if s.count(',') > 1:
            s = s.replace(',', '')
        else:
            left, right = s.rsplit(',', 1)
            if len(right) in (1, 2):
                s = left.replace(',', '') + '.' + right
            else:
                s = s.replace(',', '')
    elif '.' in s and s.count('.') > 1:
        parts = s.split('.')
        s = ''.join(parts[:-1]) + '.' + parts[-1]
    try:
        return float(s)
    except ValueError:
        return None


def numbers_in_line(line):
    vals = []
    for tok in num_pat.findall(line):
        val = normalize_number(tok)
        if val is not None:
            vals.append(val)
    return vals


def classify(text):
    t = text.lower()
    score = sum(bool(re.search(p, t)) for p in invoice_indicators)
    return 'invoice' if score >= 2 or ('invoice' in t and ('totalprice' in t or 'amount due' in t or 'bill to' in t)) else 'other'


def parse_invoice_amounts(text):
    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    candidates = {'total': [], 'amount_due': [], 'grand_total': [], 'vat': []}

    for i, line in enumerate(lines):
        l = line.lower()
        same = numbers_in_line(line)
        nxt = numbers_in_line(lines[i+1]) if i + 1 < len(lines) else []

        if 'totalprice' in l:
            if same:
                candidates['total'].append(same[-1])
            elif nxt:
                candidates['total'].append(nxt[0])
            continue

        if 'grand total' in l:
            if same:
                candidates['grand_total'].append(same[-1])
            elif nxt:
                candidates['grand_total'].append(nxt[0])

        if 'amount due' in l:
            if same:
                candidates['amount_due'].append(same[-1])
            elif nxt:
                candidates['amount_due'].append(nxt[0])

        if re.search(r'\btotal\b', l) and 'subtotal' not in l and 'grand total' not in l and 'totalprice' not in l:
            # For lines like "Total $ net $ vat $ gross", use the last value.
            if same:
                candidates['total'].append(same[-1])
            elif nxt:
                candidates['total'].append(nxt[0])

        if ('vat' in l or re.search(r'\bgst\b', l) or ('tax' in l and 'tax id' not in l)):
            if len(same) >= 2 and re.search(r'\btotal\b', l):
                candidates['vat'].append(same[-2])
            elif same:
                candidates['vat'].append(same[-1])
            elif nxt:
                vals = nxt
                candidates['vat'].append(vals[-2] if len(vals) >= 2 else vals[-1])

    total = None
    if candidates['grand_total']:
        total = candidates['grand_total'][-1]
    if candidates['amount_due'] and total is None:
        total = candidates['amount_due'][-1]
    if candidates['total']:
        total = candidates['total'][-1]

    vat = candidates['vat'][-1] if candidates['vat'] else 0.0
    return total if total is not None else 0.0, vat


def fmt(n):
    return f'{n:.2f}'

texts = {}
rows = []

total_total = 0.0
total_vat = 0.0

for name in sorted(os.listdir(DOCS)):
    src = os.path.join(DOCS, name)
    text = extract_text(src)
    texts[name] = text
    dest_dir = INV if classify(text) == 'invoice' else OTH
    shutil.move(src, os.path.join(dest_dir, name))

for name in sorted(os.listdir(INV)):
    if name == 'summary.csv':
        continue
    path = os.path.join(INV, name)
    text = texts.get(name) or extract_text(path)
    total_amount, vat_amount = parse_invoice_amounts(text)
    rows.append([name, fmt(total_amount), fmt(vat_amount)])
    total_total += total_amount
    total_vat += vat_amount

with open(os.path.join(INV, 'summary.csv'), 'w', newline='') as f:
    writer = csv.writer(f)
    writer.writerow(['filename', 'total_amount', 'vat_amount'])
    writer.writerows(rows)
    writer.writerow(['total', fmt(total_total), fmt(total_vat)])

print('Moved invoices:', sorted(os.listdir(INV)))
print('Moved others:', sorted(os.listdir(OTH)))
print('Summary rows:', len(rows))
